@vex.guardrail(name='loop_detection')
def detect_circular_delegation(session_history: list) -> bool:
    recent_calls = session_history[-5:]
    agents = [call['agent'] for call in recent_calls]

    # Detect loops: same agent sequence repeating
    if len(set(tuple(agents[i:i+3]) for i in range(len(agents)-2))) < 2:
        return False
    return True

router.add_callback(detect_circular_delegation)

@vex.guardrail(name='research_verification')
def verify_sources(sources: list) -> dict:
    results = []
    for source in sources:
        checks = {
            'recency': (datetime.now() - source['date']).days <= 90,
            'domain_reputation': source['domain'] in TRUSTED_DOMAINS,
            'claim_support': analyze_claim_support(source['content']),
            'bias_score': detect_bias(source['content'])
        }
        if all([checks['recency'], checks['domain_reputation'], checks['bias_score'] < 0.7]):
            results.append(source)
    return {'verified_sources': results, 'failed': len(sources) - len(results)}
